from transformers import SegformerForSemanticSegmentation, SegformerConfig
import torch.nn as nn


class WrappedSegformer(nn.Module):
    def __init__(self, num_classes=150, pretrained=False, id2label=None, label2id=None):
        super().__init__()
        if pretrained:
            self.model = SegformerForSemanticSegmentation.from_pretrained(
                'nvidia/mit-b5',
                num_labels=num_classes,
                ignore_mismatched_sizes=True,
                id2label=id2label,
                label2id=label2id,
            )
        else:
            cfg = SegformerConfig.from_pretrained('nvidia/mit-b5')
            cfg.num_labels = num_classes
            if id2label is not None:
                cfg.id2label = id2label
            if label2id is not None:
                cfg.label2id = label2id
            self.model = SegformerForSemanticSegmentation(cfg)

    def forward(self, pixel_values):
        return self.model(pixel_values=pixel_values)


def build_model(num_classes=150, pretrained=False, id2label=None, label2id=None, **kwargs):
    return WrappedSegformer(
        num_classes=num_classes,
        pretrained=pretrained,
        id2label=id2label,
        label2id=label2id,
    )
